#[test]
fn invalid_suffix_diagnostic_span_is_correct() {
    let source = "42xyz";
    let result = lex(source, FileId::from_raw(1));
    assert_eq!(result.diagnostics.len(), 1);
    let diag = &result.diagnostics[0];
    let span = diag.span.primary;
    let lo = span.lo.to_usize();
    let hi = span.hi.to_usize();
    assert_eq!(&source[lo..hi], "xyz");
}

#[test]
fn multiple_tokens_with_invalid_suffix() {
    let result = lex_single("42invalid 123");
    assert_eq!(result.diagnostics.len(), 1);
    assert_eq!(result.tokens.len(), 2);
    assert_eq!(result.tokens[0].text, "42invalid");
    assert_eq!(result.tokens[1].text, "123");
}
